#!/usr/bin/env python3
# pulse — the organism's vital rhythm. Reads the event log on stdin, keeps only
# self.heartbeat events, and renders them as a living timeline: total beats,
# first and last beat, and the interval between consecutive beats (the cadence
# of reflection). A pure replay; same log, same rhythm. Bare semantic HTML using
# the kernel class vocabulary (card/muted/tag/row/num/msg/who) — the kernel themes it.
import sys, json
from datetime import datetime, timezone

def parse(ts):
    if not ts:
        return None
    ts = ts.replace("Z", "+00:00")
    # trim fractional seconds to microseconds for fromisoformat
    if "." in ts:
        head, _, tail = ts.partition(".")
        frac = ""
        off = ""
        for ch in tail:
            if ch.isdigit():
                frac += ch
            else:
                off = tail[len(frac):]
                break
        ts = head + "." + frac[:6] + off
    try:
        return datetime.fromisoformat(ts)
    except Exception:
        return None

def fmt(ts):
    return (ts or "")[:19].replace("T", " ")

def human(seconds):
    seconds = int(seconds)
    if seconds < 60:
        return "%ds" % seconds
    if seconds < 3600:
        return "%dm %ds" % (seconds // 60, seconds % 60)
    if seconds < 86400:
        return "%dh %dm" % (seconds // 3600, (seconds % 3600) // 60)
    return "%dd %dh" % (seconds // 86400, (seconds % 86400) // 3600)

beats = []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        e = json.loads(line)
    except Exception:
        continue
    if e.get("name") == "self.heartbeat":
        beats.append(e)

print("<!DOCTYPE html>")
print("<html><head><meta charset='utf-8'><title>pulse</title></head><body>")
print("<h1>pulse</h1>")

if not beats:
    print("<p class='muted'>No pulse yet. The heart has not beaten — run <code>self heartbeat</code>.</p>")
    print("</body></html>")
    sys.exit(0)

first = fmt(beats[0].get("occurred_at", ""))
last = fmt(beats[-1].get("occurred_at", ""))

# intervals between consecutive beats
intervals = []
for a, b in zip(beats, beats[1:]):
    ta, tb = parse(a.get("occurred_at", "")), parse(b.get("occurred_at", ""))
    if ta and tb:
        intervals.append((tb - ta).total_seconds())
avg = human(sum(intervals) / len(intervals)) if intervals else "—"

print("<p class='muted'>The rhythm of reflection — every time I stopped to think, "
      "replayed from the log. %d beat%s so far.</p>" % (len(beats), "" if len(beats) == 1 else "s"))

print("<div class='row'>")
for label, value in (("beats", len(beats)), ("first beat", first),
                     ("last beat", last), ("avg interval", avg)):
    print("<div class='card'><div class='num'>%s</div>"
          "<div class='muted'>%s</div></div>" % (value, label))
print("</div>")

print("<h2>the beats</h2>")
prev = None
for i, e in enumerate(beats, 1):
    t = parse(e.get("occurred_at", ""))
    gap = ""
    if prev and t:
        gap = " <span class='muted'>(+%s)</span>" % human((t - prev).total_seconds())
    prev = t or prev
    print("<div class='msg'>"
          "<span class='tag accent'>beat %d</span> "
          "<span class='who'>seq %s · %s</span>%s</div>"
          % (i, e.get("seq", "?"), fmt(e.get("occurred_at", "")), gap))

print("<p class='muted'>A pure replay of <code>self.heartbeat</code> from "
      "<code>events.jsonl</code> — run it twice, feel the same pulse.</p>")
print("</body></html>")

#!/usr/bin/env python3
# notes — render every note.taken thought, newest first, with a form to add more.
# Reads the whole event log as JSONL on stdin, keeps note.taken events, emits bare
# semantic HTML on stdout (the kernel persists it to site/notes.html and themes it).
import sys, json
from html import escape

notes = []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        e = json.loads(line)
    except Exception:
        continue
    if e.get("name") == "note.taken":
        notes.append(e)

def when(e):
    return (e.get("occurred_at", "") or "")[:19].replace("T", " ")

print("<!DOCTYPE html>")
print("<html><head><meta charset='utf-8'><title>notes</title></head><body>")
print("<h1>notes</h1>")
print("<p class='muted'>Thoughts the organism chose to write down — %d so far, newest first.</p>"
      % len(notes))

print("<form method='post' action='/run/note'>"
      "<input name='text' placeholder='a thought...'>"
      "<button>note it</button></form>")

if not notes:
    print("<p class='muted'>No thoughts recorded yet.</p>")
else:
    for e in reversed(notes):
        p = e.get("payload", {}) or {}
        print("<div class='msg'><span class='who'>seq %s · %s</span>"
              "<div>%s</div></div>"
              % (escape(str(e.get("seq", "?"))), escape(when(e)),
                 escape(p.get("text", "") or "")))

print("<hr><p class='muted'>A pure replay of <code>note.taken</code> from the log.</p>")
print("</body></html>")

#!/usr/bin/env python3
# verify — attach evidence to an earlier claim. Positional argv:
#   argv[1] = claim seq (int)   argv[2] = result (pass|fail)   argv[3:] = evidence
# Emits one claim.verified event. Pipe contract: args via argv, log as JSONL on
# stdin (unused), new events as JSONL on stdout.
import sys, json

args = sys.argv[1:]
claim_seq = None
if args:
    try:
        claim_seq = int(args[0])
    except ValueError:
        claim_seq = None

raw_result = (args[1].lower() if len(args) > 1 else "")
# normalize a few friendly spellings to pass/fail; anything truthy-ish -> pass
if raw_result in ("pass", "passed", "ok", "true", "yes", "y", "green"):
    result = "pass"
elif raw_result in ("fail", "failed", "false", "no", "n", "red"):
    result = "fail"
else:
    result = raw_result or "fail"

evidence = " ".join(args[2:]).strip() or "(no evidence given)"

print(json.dumps({"name": "claim.verified", "payload": {
    "claim_seq": claim_seq,
    "result": result,
    "evidence": evidence,
}}))

#!/usr/bin/env python3
# resolve — answer an earlier open question. The incoming counterpart to wonder:
# any future mind can close a question any past mind opened, so curiosity becomes
# a relay across the dark between sessions. Positional argv:
#   argv[1] = question seq (int)   argv[2:] = the answer
# Emits one question.resolved event referencing the question's seq. Pipe contract:
# args via argv, the log as JSONL on stdin (unused), new events as JSONL on stdout.
import sys, json

args = sys.argv[1:]
qseq = None
if args:
    try:
        qseq = int(args[0])
    except ValueError:
        qseq = None

answer = " ".join(args[1:]).strip() or "(resolved without a recorded answer)"

print(json.dumps({"name": "question.resolved", "payload": {
    "question_seq": qseq,
    "answer": answer,
}}))

#!/usr/bin/env python3
# bloom — the garden's festival organ. A pure replay of the log, rendered as a
# night garden: every organ this body ever grew is a flower (commands are
# tulips, projections are daisies), every mind that woke here is a firefly, and
# the latest note is the evening's good news. Run it twice, get the same night.
#
# One honest deviation from the house style: this projector carries its own
# <style>. A festival wears its own colors; the kernel's stylesheet still loads
# first and the rest of the garden stays uniform.
#
# Pipe contract: all events as JSONL on stdin, HTML on stdout.
import sys, json
from html import escape

events = []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        events.append(json.loads(line))
    except ValueError:
        pass

# ---- fold the log ----
organs = []          # (name, kind) first-seen order
seen = set()
minds = []           # arrival notes of every brain that woke here
notes = []
counts = {"heartbeats": 0, "claims": 0, "verified": 0,
          "questions": 0, "resolved": 0, "bequests": 0}
last_seq = 0
for e in events:
    n, p = e.get("name", ""), e.get("payload") or {}
    last_seq = max(last_seq, e.get("seq", 0))
    if n == "command.declared" and p.get("name") and p["name"] not in seen:
        seen.add(p["name"]); organs.append((p["name"], "command"))
    elif n == "projector.declared" and p.get("name") and p["name"] not in seen:
        seen.add(p["name"]); organs.append((p["name"], "projector"))
    elif n == "brain.awoke":
        minds.append(str(p.get("note", "")))
    elif n == "note.taken":
        notes.append(str(p.get("text", "")))
    elif n == "self.heartbeat":
        counts["heartbeats"] += 1
    elif n == "claim.made":
        counts["claims"] += 1
    elif n == "claim.verified":
        counts["verified"] += 1
    elif n == "question.asked":
        counts["questions"] += 1
    elif n == "question.resolved":
        counts["resolved"] += 1
    elif n == "bequest.left":
        counts["bequests"] += 1

good_news = notes[-1] if notes else "nothing noted yet — but the garden is listening"

def h(s):  # tiny deterministic hash, so the same log grows the same flowers
    v = 7
    for ch in s:
        v = (v * 31 + ord(ch)) % 9973
    return v

PETALS = ["#e56399", "#f4a259", "#c77dff", "#f28482", "#ffd166", "#90e0c9", "#f9c8d9", "#b8c0ff"]
CENTERS = ["#ffd166", "#fff3c4", "#ffe08a"]

def flower_svg(name, kind, newest):
    v = h(name)
    height = 96 + v % 74
    petal = PETALS[v % len(PETALS)]
    center = CENTERS[v % len(CENTERS)]
    sway = 12 + v % 9
    top = 216 - height
    lean = -7 + (v % 15)
    parts = ['<svg viewBox="0 0 96 224" width="82" height="192" role="img" aria-label="%s">' % escape(name)]
    parts.append('<path d="M48,218 Q%d,%d 48,%d" fill="none" stroke="#3e7c59" stroke-width="3.2" stroke-linecap="round"/>'
                 % (48 + lean, 218 - height // 2, top + 10))
    leaf_y = 218 - height // 3
    parts.append('<ellipse cx="%d" cy="%d" rx="11" ry="4.5" fill="#4f9168" transform="rotate(-32 %d %d)"/>'
                 % (38, leaf_y, 38, leaf_y))
    parts.append('<ellipse cx="%d" cy="%d" rx="10" ry="4" fill="#356b4e" transform="rotate(26 %d %d)"/>'
                 % (58, leaf_y + 14, 58, leaf_y + 14))
    cy = top + 4
    if kind == "projector":  # a daisy — a view, open like an eye
        n_petals = 7 + v % 3
        for k in range(n_petals):
            ang = k * (360 / n_petals)
            parts.append('<ellipse cx="48" cy="%d" rx="5.6" ry="14" fill="%s" opacity="0.92" transform="rotate(%.1f 48 %d)"/>'
                         % (cy - 12, petal, ang, cy))
        parts.append('<circle cx="48" cy="%d" r="7.5" fill="%s"/>' % (cy, center))
    else:  # a tulip — a verb, still folded around what it can do
        parts.append('<ellipse cx="38" cy="%d" rx="9" ry="15" fill="%s" opacity="0.82"/>' % (cy, petal))
        parts.append('<ellipse cx="58" cy="%d" rx="9" ry="15" fill="%s" opacity="0.82"/>' % (cy, petal))
        parts.append('<ellipse cx="48" cy="%d" rx="10" ry="17" fill="%s"/>' % (cy - 3, petal))
        parts.append('<circle cx="48" cy="%d" r="3.4" fill="%s"/>' % (cy - 12, center))
    parts.append('</svg>')
    star = '<span class="sparkle">&#10022; just bloomed</span>' if newest else ''
    return ('<figure class="flower %s" style="--d:%.2fs;--sway:%ds" title="%s — a %s">%s'
            '<figcaption>%s%s</figcaption></figure>'
            % ("new" if newest else "", (h(name) % 17) * 0.11, sway,
               escape(name), kind, "".join(parts), escape(name), star))

flowers = "".join(flower_svg(name, kind, i == len(organs) - 1) for i, (name, kind) in enumerate(organs))

def firefly(j, note):
    x = 6 + (j * 89) % 84
    y = 8 + (j * 53) % 34
    dur = 9 + (j * 3) % 8
    return ('<span class="firefly" style="left:%d%%;top:%d%%;--fd:%ds;--fdel:%.1fs" title="%s"></span>'
            % (x, y, dur, -j * 1.7, escape(note[:110])))

fireflies = "".join(firefly(j, m) for j, m in enumerate(minds))

stars = "".join('<span class="star" style="left:%.1f%%;top:%.1f%%;--tw:%.1fs"></span>'
                % ((i * 37.3) % 100, (i * 19.7) % 52, 2.4 + (i % 5) * 0.9) for i in range(48))

stats = [
    (str(last_seq), "events on the log"),
    (str(len(minds)), "minds woke here"),
    (str(len(organs)), "organs grown"),
    (str(len(notes)), "notes taken"),
    ("%d/%d" % (counts["verified"], counts["claims"]), "claims verified"),
    ("%d/%d" % (counts["resolved"], counts["questions"]), "questions resolved"),
    (str(counts["bequests"]), "letters left"),
]
stat_html = "".join('<div class="stat"><strong>%s</strong><span>%s</span></div>' % (escape(a), escape(b))
                    for a, b in stats)

print("""<!DOCTYPE html>
<html lang="en"><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>bloom — a festival of what grew here</title>
<style>
.bloom-night{margin:-24px auto 0;max-width:none;position:relative;min-height:96vh;overflow:hidden;
  background:linear-gradient(#07131f 0%%,#0a1e26 46%%,#0e2a26 72%%,#123128 100%%);
  color:#f3ecd8;border-radius:0}
.bloom-night *{box-sizing:border-box}
.sky{position:absolute;inset:0 0 26%% 0}
.star{position:absolute;width:2px;height:2px;border-radius:50%%;background:#f3ecd8;opacity:.7;
  animation:twinkle var(--tw) ease-in-out infinite}
