#!/usr/bin/env python3
# graze — one observation pass over herdr, the agent terminal multiplexer.
# herdr is the authority on the PRESENT (which workspaces and panes exist,
# whether each agent is blocked / working / done / idle) and only the present:
# it forgets a pane the moment it closes. This body is nothing but memory. So
# graze reads herdr's live state — read-only, never driving it — and appends
# what it saw as herd.observed, stacking herdr's present into a past the herd
# projection can replay. When a brain is reachable and there are agents to
# understand, graze also asks it (through 'self think', with the log's standing
# herd.doctrine as the lens) for one-breath digests of what each agent is
# building (herd.digest) and a coherence narrative per filed domain (herd.arc).
# Every degradation is honest: no herdr → status "absent" (and the projection
# points at herdr.dev); herdr installed but nothing live → "quiet"; no brain →
# observations without digests, never guessed ones. Nothing here hardcodes
# herdr's schema: discovery probes the CLI, then conventional socket and state
# paths, and records HOW it observed (via) so the page can say so. Pipe
# contract: args via argv (unused), the log as JSONL on stdin, new events as
# JSONL on stdout (fields: name, payload); the kernel assigns id/seq/occurred_at.
import glob
import json
import os
import shutil
import subprocess
import sys

HOME = os.path.expanduser("~")


def read_log():
    events = []
    for line in sys.stdin:
        line = line.strip()
        if line:
            try:
                events.append(json.loads(line))
            except ValueError:
                pass
    return events


def probe_sockets():
    pats = []
    xrd = os.environ.get("XDG_RUNTIME_DIR")
    if xrd:
        pats += [os.path.join(xrd, "herdr*"), os.path.join(xrd, "herdr", "*")]
    pats += [os.path.join(HOME, ".herdr", "*.sock"),
             "/tmp/herdr*", "/tmp/herdr*/*"]
    found = []
    for p in pats:
        for f in glob.glob(p):
            try:
                import stat
                if stat.S_ISSOCK(os.stat(f).st_mode):
                    found.append(f)
            except OSError:
                pass
    return sorted(set(found))


def probe_state_dirs():
    cands = [os.path.join(os.environ.get("XDG_STATE_HOME", os.path.join(HOME, ".local", "state")), "herdr"),
             os.path.join(os.environ.get("XDG_DATA_HOME", os.path.join(HOME, ".local", "share")), "herdr"),
             os.path.join(HOME, ".herdr")]
    return [d for d in cands if os.path.isdir(d)]


def try_cli(binary):
    # Best-effort, read-only: ask herdr to list what it manages, preferring
    # machine output. Subcommands vary across versions; probe a few, never mutate.
    for args in (["ls", "--json"], ["list", "--json"], ["status", "--json"], ["ls"]):
        try:
            r = subprocess.run([binary] + args, capture_output=True, text=True, timeout=10)
        except Exception:
            continue
        out = (r.stdout or "").strip()
        if r.returncode != 0 or not out:
            continue
        try:
            return "cli:" + " ".join(args), json.loads(out)
        except ValueError:
            return "cli:" + " ".join(args), {"raw": out[:4000]}
    return None, None


def read_sessions(state_dirs):
    # herdr persists sessions as plain JSON on local disk; read them as found,
    # keeping only shallow, obviously-metadata fields. Schema is not assumed.
    sessions = []
    for d in state_dirs:
        for f in sorted(glob.glob(os.path.join(d, "**", "*.json"), recursive=True))[:40]:
            try:
                with open(f) as fh:
                    data = json.load(fh)
                sessions.append({"file": os.path.relpath(f, d), "data": data})
            except Exception:
                pass
    return sessions


STATES = ("blocked", "working", "done", "idle")


def normalize(raw):
    # Fold whatever shape discovery produced into workspaces/agents, keeping
    # unknown states as-is rather than inventing certainty.
    workspaces, agents = [], []

    def walk(node, ws=None):
        if isinstance(node, dict):
            name = node.get("name") or node.get("title") or node.get("id")
            state = str(node.get("state") or node.get("status") or "").lower()
            agent = node.get("agent") or node.get("command") or node.get("program")
            if state in STATES or agent:
                agents.append({"workspace": ws or "(unfiled)",
                               "agent": str(agent or name or "?"),
                               "state": state if state in STATES else (state or "unknown"),
                               "title": str(node.get("title") or "")})
            kids_keys = ("workspaces", "tabs", "panes", "sessions", "agents", "children")
            for k in kids_keys:
                v = node.get(k)
                if isinstance(v, list):
                    next_ws = name if k in ("tabs", "panes", "agents", "children") and name else ws
                    if k == "workspaces":
                        for w in v:
                            wn = (w or {}).get("name") or (w or {}).get("id") or "?"
                            workspaces.append(str(wn))
                            walk(w, str(wn))
                    else:
                        for c in v:
                            walk(c, next_ws)
        elif isinstance(node, list):
            for c in node:
                walk(c, ws)

    walk(raw)
    for a in agents:
        if a["workspace"] not in workspaces and a["workspace"] != "(unfiled)":
            workspaces.append(a["workspace"])
    return workspaces, agents


def think(prompt):
    binary = shutil.which("self")
    if not binary:
        cand = os.path.join(os.path.dirname(os.environ.get("SELF_HOME", "")), "self")
        binary = cand if os.access(cand, os.X_OK) else None
    if not binary:
        return None
    try:
        r = subprocess.run([binary, "think", prompt], capture_output=True, text=True, timeout=540)
        if r.returncode != 0:
            return None
        return json.loads(r.stdout).get("response")
    except Exception:
        return None


def emit(name, payload):
    sys.stdout.write(json.dumps({"name": name, "payload": payload}) + "\n")


def main():
    log = read_log()
    doctrine = ""
    filings = {}
    for e in log:
        if e.get("name") == "herd.doctrine":
            doctrine = e.get("payload", {}).get("text", "")
        if e.get("name") == "herd.filed":
            p = e.get("payload", {})
            filings[p.get("workspace", "")] = p.get("domain", "")

    binary = shutil.which("herdr")
    sockets = probe_sockets()
    state_dirs = probe_state_dirs()

    via, raw = (None, None)
    if binary:
        via, raw = try_cli(binary)
    sessions = read_sessions(state_dirs) if raw is None else []
    if raw is None and sessions:
        via, raw = "sessions", [s["data"] for s in sessions]

    workspaces, agents = normalize(raw) if raw is not None else ([], [])

    if not binary and not sockets and not state_dirs:
        status, note = "absent", "no herdr on this machine — no binary on PATH, no socket, no state dir"
    elif not agents:
        status, note = "quiet", "herdr is installed here but nothing is live to observe"
    else:
        status, note = "present", "observed %d agent(s) across %d workspace(s)" % (len(agents), len(workspaces))

    counts = {s: sum(1 for a in agents if a["state"] == s) for s in STATES}
    emit("herd.observed", {
        "status": status, "via": via or "none", "note": note,
        "herdr": binary or "", "sockets": sockets, "state_dirs": state_dirs,
        "workspaces": workspaces, "agents": agents, "counts": counts,
    })

    # Digests and arcs only when there is something real to digest and a brain
    # to digest it — never guessed, never faked.
    if agents:
        lens = ("Your standing doctrine for watching the herd:\n" + doctrine + "\n\n") if doctrine else ""
        for a in agents[:12]:
            text = think(lens + "In one breath (one or two sentences), what is this agent building "
                         "and where is it stuck, judging only from this metadata? Answer 'I can't tell yet' "
                         "if the metadata is not enough.\n" + json.dumps(a))
            if text:
                emit("herd.digest", {"workspace": a["workspace"], "agent": a["agent"], "text": text.strip()})
        domains = sorted(set(filings.get(w) for w in workspaces if filings.get(w)))
        for d in domains:
            ws = [w for w in workspaces if filings.get(w) == d]
            text = think(lens + "Domain %r holds workspaces %s. In two or three sentences: what is being "
                         "built in this domain, and does today's herd activity cohere with that direction "
                         "or wander from it? Say a change of direction as news, never hide it in averages.\n"
                         % (d, ws) + json.dumps([a for a in agents if a["workspace"] in ws]))
            if text:
                emit("herd.arc", {"domain": d, "text": text.strip()})


main()

