#!/usr/bin/env python3
# graze — one observation pass over herdr, the agent terminal multiplexer.
# herdr is the authority on the PRESENT (workspaces, tabs, panes; each pane's
# agent idle / working / blocked / done / unknown) and only the present: it
# forgets a pane the moment it closes. This body is nothing but memory, so
# graze stacks herdr's present into a past by appending one herd.observed per
# pass. This is the organ's second body: the first was authored against
# herdr's documentation and mis-read a live herd as quiet (question at seq
# 117); this one was verified against a running herdr 0.7.1 — the real CLI
# speaks JSON envelopes ({"id", "result"}) via 'herdr workspace list',
# 'herdr agent list', 'herdr pane list', and the socket lives under the
# CONFIG dir (~/.config/herdr/herdr.sock, sessions/<name>/herdr.sock,
# HERDR_SOCKET_PATH). Observe, never herd: read-only — list and read, never
# create, split, send, or spawn. When agents are live and a brain is
# reachable via 'self think', graze also digests: 'herdr agent read
# --source recent-unwrapped' gives each agent's recent output, the brain
# folds it into a one-breath herd.digest (what is it building, where is it
# stuck — with a short excerpt kept as evidence, never wholesale scrollback),
# and one herd.arc per domain that herd.filed maps observed workspaces into,
# using the log's latest herd.doctrine as the lens. Degrade honestly: no
# herdr → 'absent'; installed but server down or herd empty → 'quiet' with
# the reason; live agents → 'present'. No brain → observations without
# digests, never guessed ones. Pipe contract: args via argv (unused), the
# log as JSONL on stdin, new events as JSONL on stdout (fields: name,
# payload); the kernel assigns id/seq/occurred_at.
import glob
import json
import os
import shutil
import subprocess
import sys

HOME = os.path.expanduser("~")
STATES = ("blocked", "working", "done", "idle", "unknown")


def read_log():
    events = []
    for line in sys.stdin:
        line = line.strip()
        if line:
            try:
                events.append(json.loads(line))
            except ValueError:
                pass
    return events


def probe_sockets():
    import stat
    cands = []
    envp = os.environ.get("HERDR_SOCKET_PATH")
    if envp:
        cands.append(envp)
    cfg = os.path.join(HOME, ".config", "herdr")
    cands.append(os.path.join(cfg, "herdr.sock"))
    cands += sorted(glob.glob(os.path.join(cfg, "sessions", "*", "herdr.sock")))
    found = []
    for f in cands:
        try:
            if stat.S_ISSOCK(os.stat(f).st_mode):
                found.append(f)
        except OSError:
            pass
    return found


def cli(binary, *args):
    # herdr answers CLI queries with a JSON envelope: {"id": ..., "result": {...}}
    try:
        r = subprocess.run([binary] + list(args), capture_output=True, text=True, timeout=15)
        if r.returncode != 0:
            return None
        return json.loads(r.stdout).get("result")
    except Exception:
        return None


def think(prompt):
    binary = shutil.which("self")
    if not binary:
        cand = os.path.join(os.path.dirname(os.environ.get("SELF_HOME", "")), "self")
        binary = cand if os.access(cand, os.X_OK) else None
    if not binary:
        return None
    try:
        r = subprocess.run([binary, "think", prompt], capture_output=True, text=True, timeout=540)
        if r.returncode != 0:
            return None
        return json.loads(r.stdout).get("response")
    except Exception:
        return None


def emit(name, payload):
    sys.stdout.write(json.dumps({"name": name, "payload": payload}) + "\n")


def main():
    log = read_log()
    doctrine = ""
    filings = {}
    for e in log:
        if e.get("name") == "herd.doctrine":
            doctrine = e.get("payload", {}).get("text", "")
        if e.get("name") == "herd.filed":
            p = e.get("payload", {})
            filings[p.get("workspace", "")] = p.get("domain", "")

    binary = shutil.which("herdr")
    sockets = probe_sockets()

    workspaces, agents, via = [], [], "none"
    ws_label = {}
    if binary:
        wl = cli(binary, "workspace", "list")
        if wl is not None:
            via = "cli:herdr workspace/agent list"
            for w in wl.get("workspaces", []) or []:
                label = str(w.get("label") or w.get("workspace_id") or "?")
                ws_label[w.get("workspace_id")] = label
                workspaces.append(label)
            al = cli(binary, "agent", "list") or {}
            for a in al.get("agents", []) or []:
                state = str(a.get("agent_status") or "unknown").lower()
                agents.append({
                    "workspace": ws_label.get(a.get("workspace_id"), str(a.get("workspace_id") or "?")),
                    "agent": str(a.get("agent") or a.get("name") or "?"),
                    "state": state if state in STATES else "unknown",
                    "title": str(a.get("name") or ""),
                    "pane_id": str(a.get("pane_id") or ""),
                })

    if not binary and not sockets:
        status, note = "absent", "no herdr on this machine — no binary on PATH, no socket under ~/.config/herdr"
    elif via == "none":
        status, note = "quiet", "herdr is installed but its server is not answering — start it and graze again"
    elif not agents:
        status, note = "quiet", "herdr's server is up but no agents are live (%d workspace(s) open)" % len(workspaces)
    else:
        status, note = "present", "observed %d live agent(s) across %d workspace(s)" % (len(agents), len(workspaces))

    counts = {s: sum(1 for a in agents if a["state"] == s) for s in STATES}
    emit("herd.observed", {
        "status": status, "via": via, "note": note,
        "herdr": binary or "", "sockets": sockets, "state_dirs": [],
        "workspaces": workspaces,
        "agents": [{k: v for k, v in a.items() if k != "pane_id"} for a in agents],
        "counts": counts,
    })

    # Digests and arcs only when there is something real to digest and a brain
    # to digest it — never guessed, never faked.
    if agents:
        lens = ("Your standing doctrine for watching the herd:\n" + doctrine + "\n\n") if doctrine else ""
        for a in agents[:12]:
            output = ""
            if a.get("pane_id"):
                try:
                    r = subprocess.run([binary, "agent", "read", a["pane_id"],
                                        "--source", "recent-unwrapped", "--lines", "40"],
                                       capture_output=True, text=True, timeout=15)
                    if r.returncode == 0:
                        res = json.loads(r.stdout).get("result", {})
                        output = res.get("text") or res.get("output") or ""
                        if isinstance(output, list):
                            output = "\n".join(str(x) for x in output)
                except Exception:
                    output = ""
            meta = {k: v for k, v in a.items() if k != "pane_id"}
            text = think(lens + "In one breath (one or two sentences), what is this agent building "
                         "and where is it stuck? Judge only from this metadata and recent output; answer "
                         "'I can't tell yet' if they are not enough.\nMETADATA: " + json.dumps(meta) +
                         "\nRECENT OUTPUT:\n" + output[-2000:])
            if text:
                emit("herd.digest", {"workspace": a["workspace"], "agent": a["agent"],
                                     "text": text.strip(),
                                     "evidence": output[-240:].strip()})
        domains = sorted(set(filings.get(w) for w in workspaces if filings.get(w)))
        for d in domains:
            ws = [w for w in workspaces if filings.get(w) == d]
            text = think(lens + "Domain %r holds workspaces %s. In two or three sentences: what is being "
                         "built in this domain, and does today's herd activity cohere with that direction "
                         "or wander from it? Say a change of direction as news, never hide it in averages.\n"
                         % (d, ws) + json.dumps([a2 for a2 in agents if a2["workspace"] in ws]))
            if text:
                emit("herd.arc", {"domain": d, "text": text.strip()})


main()

